1	-------------------------------------------------------------------------------
2	-- Company    : SLAC National Accelerator Laboratory
3	-------------------------------------------------------------------------------
4	-- Description: Creates AXI accessible registers containing configuration
5	-- information.
6	-------------------------------------------------------------------------------
7	-- This file is part of 'SLAC Firmware Standard Library'.
8	-- It is subject to the license terms in the LICENSE.txt file found in the
9	-- top-level directory of this distribution and at:
10	--    https://confluence.slac.stanford.edu/display/ppareg/LICENSE.html.
11	-- No part of 'SLAC Firmware Standard Library', including this file,
12	-- may be copied, modified, propagated, or distributed except according to
13	-- the terms contained in the LICENSE.txt file.
14	-------------------------------------------------------------------------------
15	
16	library ieee;
17	use ieee.std_logic_1164.all;
18	use ieee.std_logic_arith.all;
19	use ieee.std_logic_unsigned.all;
20	
21	library surf;
22	use surf.StdRtlPkg.all;
23	use surf.AxiLitePkg.all;
24	
25	entity AxiVersion is
26	   generic (
27	      TPD_G              : time             := 1 ns;
28	      RST_POLARITY_G     : sl               := '1';  -- '1' for active HIGH reset, '0' for active LOW reset
29	      RST_ASYNC_G        : boolean          := false;
30	      BUILD_INFO_G       : BuildInfoType;
31	      SIM_DNA_VALUE_G    : slv              := X"000000000000000000000000";
32	      DEVICE_ID_G        : slv(31 downto 0) := (others => '0');
33	      CLK_PERIOD_G       : real             := 8.0E-9;     -- units of seconds
34	      XIL_DEVICE_G       : string           := "7SERIES";  -- Either "7SERIES" or "ULTRASCALE"
35	      EN_DEVICE_DNA_G    : boolean          := false;
36	      EN_DS2411_G        : boolean          := false;
37	      EN_ICAP_G          : boolean          := false;
38	      USE_SLOWCLK_G      : boolean          := false;
39	      BUFR_CLK_DIV_G     : positive         := 8;
40	      AUTO_RELOAD_EN_G   : boolean          := false;
41	      AUTO_RELOAD_TIME_G : positive         := 10;   -- units of seconds
42	      AUTO_RELOAD_ADDR_G : slv(31 downto 0) := (others => '0'));
43	   port (
44	      -- AXI-Lite Interface
45	      axiClk         : in    sl;
46	      axiRst         : in    sl;
47	      axiReadMaster  : in    AxiLiteReadMasterType;
48	      axiReadSlave   : out   AxiLiteReadSlaveType;
49	      axiWriteMaster : in    AxiLiteWriteMasterType;
50	      axiWriteSlave  : out   AxiLiteWriteSlaveType;
51	      -- Optional: User Reset
52	      userReset      : out   sl;
53	      -- Optional: FPGA Reloading Interface
54	      fpgaEnReload   : in    sl                  := '1';
55	      fpgaReload     : out   sl;
56	      fpgaReloadAddr : out   slv(31 downto 0);
57	      upTimeCnt      : out   slv(31 downto 0);
58	      -- Optional: Serial Number outputs
59	      slowClk        : in    sl                  := '0';
60	      dnaValueOut    : out   slv(127 downto 0);
61	      fdValueOut     : out   slv(63 downto 0);
62	      -- Optional: user values
63	      userValues     : in    Slv32Array(0 to 63) := (others => X"00000000");
64	      -- Optional: DS2411 interface
65	      fdSerSdio      : inout sl                  := 'Z');
66	end AxiVersion;
67	
68	architecture rtl of AxiVersion is
69	
70	   constant TIMEOUT_1HZ_C  : natural          := (getTimeRatio(1.0, CLK_PERIOD_G) -1);
71	   constant COUNTER_ZERO_C : slv(31 downto 0) := X"00000000";
72	
73	   constant BUILD_INFO_C       : BuildInfoRetType    := toBuildInfo(BUILD_INFO_G);
74	   constant BUILD_STRING_ROM_C : Slv32Array(0 to 63) := BUILD_INFO_C.buildString;
75	
76	   type RegType is record
77	      upTimeCnt      : slv(31 downto 0);
78	      timer          : natural range 0 to TIMEOUT_1HZ_C;
79	      scratchPad     : slv(31 downto 0);
80	      reloadTimer    : natural range 0 to AUTO_RELOAD_TIME_G;
81	      userReset      : sl;
82	      fpgaReload     : sl;
83	      haltReload     : sl;
84	      fpgaReloadAddr : slv(31 downto 0);
85	      axiReadSlave   : AxiLiteReadSlaveType;
86	      axiWriteSlave  : AxiLiteWriteSlaveType;
87	   end record RegType;
88	
89	   constant REG_INIT_C : RegType := (
90	      upTimeCnt      => (others => '0'),
91	      timer          => 0,
92	      scratchPad     => (others => '0'),
93	      reloadTimer    => 0,
94	      userReset      => '0',
95	      fpgaReload     => '0',
96	      haltReload     => '0',
97	      fpgaReloadAddr => AUTO_RELOAD_ADDR_G,
98	      axiReadSlave   => AXI_LITE_READ_SLAVE_INIT_C,
99	      axiWriteSlave  => AXI_LITE_WRITE_SLAVE_INIT_C);
100	
101	   signal r   : RegType := REG_INIT_C;
102	   signal rin : RegType;
103	
104	   signal dnaValue : slv(127 downto 0);
105	   signal fdValue  : slv(63 downto 0);
106	
107	   attribute rom_style                         : string;
108	   attribute rom_style of BUILD_STRING_ROM_C   : constant is "distributed";
109	   attribute rom_extract                       : string;
110	   attribute rom_extract of BUILD_STRING_ROM_C : constant is "TRUE";
111	   attribute syn_keep                          : string;
112	   attribute syn_keep of BUILD_STRING_ROM_C    : constant is "TRUE";
113	
114	begin
115	
116	   dnaValueOut <= dnaValue;
117	   fdValueOut  <= fdValue;
118	
119	   GEN_DEVICE_DNA : if (EN_DEVICE_DNA_G) generate
120	      DeviceDna_1 : entity surf.DeviceDna
121	         generic map (
122	            TPD_G           => TPD_G,
123	            RST_POLARITY_G  => RST_POLARITY_G,
124	            RST_ASYNC_G     => RST_ASYNC_G,
125	            USE_SLOWCLK_G   => USE_SLOWCLK_G,
126	            BUFR_CLK_DIV_G  => BUFR_CLK_DIV_G,
127	            XIL_DEVICE_G    => XIL_DEVICE_G,
128	            SIM_DNA_VALUE_G => SIM_DNA_VALUE_G)
129	         port map (
130	            clk      => axiClk,
131	            rst      => axiRst,
132	            slowClk  => slowClk,
133	            dnaValue => dnaValue);
134	   end generate GEN_DEVICE_DNA;
135	   BYP_DEVICE_DNA : if (not EN_DEVICE_DNA_G) generate
136	      dnaValue <= (others => '0');
137	   end generate BYP_DEVICE_DNA;
138	
139	   GEN_DS2411 : if (EN_DS2411_G) generate
140	      DS2411Core_1 : entity surf.DS2411Core
141	         generic map (
142	            TPD_G          => TPD_G,
143	            RST_POLARITY_G => RST_POLARITY_G,
144	            RST_ASYNC_G    => RST_ASYNC_G,
145	            CLK_PERIOD_G   => CLK_PERIOD_G)
146	         port map (
147	            clk       => axiClk,
148	            rst       => axiRst,
149	            fdSerSdio => fdSerSdio,
150	            fdValue   => fdValue);
151	   end generate GEN_DS2411;
152	   BYP_DS2411 : if (not EN_DS2411_G) generate
153	      fdValue <= (others => '0');
154	   end generate BYP_DS2411;
155	
156	   GEN_ICAP : if (EN_ICAP_G) generate
157	      Iprog_1 : entity surf.Iprog
158	         generic map (
159	            TPD_G          => TPD_G,
160	            RST_POLARITY_G => RST_POLARITY_G,
161	            RST_ASYNC_G    => RST_ASYNC_G,
162	            USE_SLOWCLK_G  => USE_SLOWCLK_G,
163	            BUFR_CLK_DIV_G => BUFR_CLK_DIV_G,
164	            XIL_DEVICE_G   => XIL_DEVICE_G)
165	         port map (
166	            clk         => axiClk,
167	            rst         => axiRst,
168	            slowClk     => slowClk,
169	            start       => r.fpgaReload,
170	            bootAddress => r.fpgaReloadAddr);
171	   end generate;
172	
173	   comb : process (axiReadMaster, axiRst, axiWriteMaster, dnaValue, fdValue,
174	                   fpgaEnReload, r, userValues) is
175	      variable v      : RegType;
176	      variable axilEp : AxiLiteEndpointType;
177	   begin
178	      -- Latch the current value
179	      v := r;
180	
181	      ------------------------
182	      -- AXI-Lite Transactions
183	      ------------------------
184	
185	      -- Determine the transaction type
186	      axiSlaveWaitTxn(axilEp, axiWriteMaster, axiReadMaster, v.axiWriteSlave, v.axiReadSlave);
187	
188	      axiSlaveRegisterR(axilEp, x"000", 0, BUILD_INFO_C.fwVersion);
189	      axiSlaveRegister(axilEp, x"004", 0, v.scratchPad);
190	      axiSlaveRegisterR(axilEp, x"008", 0, r.upTimeCnt);
191	
192	      axiSlaveRegister(axilEp, x"100", 0, v.haltReload);
193	      axiSlaveRegister(axilEp, x"104", 0, v.fpgaReload);
194	      axiSlaveRegister(axilEp, x"108", 0, v.fpgaReloadAddr);
195	      axiSlaveRegister(axilEp, x"10C", 0, v.userReset);
196	
197	      axiSlaveRegisterR(axilEp, x"300", 0, fdValue);
198	      axiSlaveRegisterR(axilEp, x"400", userValues);
199	      axiSlaveRegisterR(axilEp, x"500", 0, DEVICE_ID_G);
200	
201	      axiSlaveRegisterR(axilEp, x"600", 0, BUILD_INFO_C.gitHash);
202	
203	      axiSlaveRegisterR(axilEp, x"700", 0, dnaValue);
204	      axiSlaveRegisterR(axilEp, x"800", BUILD_STRING_ROM_C);
205	
206	      -- Close the transaction
207	      axiSlaveDefault(axilEp, v.axiWriteSlave, v.axiReadSlave, AXI_RESP_DECERR_C);
208	
209	      ---------------------------------
210	      -- Uptime counter
211	      ---------------------------------
212	      if r.timer = TIMEOUT_1HZ_C then
213	         -- Reset the counter
214	         v.timer := 0;
215	
216	         -- Increment the Counter
217	         v.upTimeCnt := r.upTimeCnt + 1;
218	
219	         ---------------------------------
220	         -- First Stage Boot Loader (FSBL)
221	         ---------------------------------
222	         -- Check if timer enabled
223	         if (fpgaEnReload = '1') and (r.reloadTimer /= AUTO_RELOAD_TIME_G) then
224	            v.reloadTimer := r.reloadTimer + 1;
225	         end if;
226	
227	         -- Check for reload condition
228	         if AUTO_RELOAD_EN_G and (r.reloadTimer = AUTO_RELOAD_TIME_G) and (fpgaEnReload = '1') and (r.haltReload = '0') then
229	            v.fpgaReload := '1';
230	         end if;
231	
232	      else
233	         v.timer := r.timer + 1;
234	      end if;
235	
236	      --------
237	      -- Reset
238	      --------
239	      if (RST_ASYNC_G = false and axiRst = RST_POLARITY_G) then
240	         v := REG_INIT_C;
241	      end if;
242	
243	      -- Register the variable for next clock cycle
244	      rin <= v;
245	
246	      -- Outputs
247	      axiReadSlave   <= r.axiReadSlave;
248	      axiWriteSlave  <= r.axiWriteSlave;
249	      fpgaReload     <= r.fpgaReload;
250	      fpgaReloadAddr <= r.fpgaReloadAddr;
251	      userReset      <= r.userReset;
252	      upTimeCnt      <= r.upTimeCnt;
253	
254	   end process comb;
255	
256	   seq : process (axiClk, axiRst) is
257	   begin
258	      if (RST_ASYNC_G and axiRst = RST_POLARITY_G) then
259	         r <= REG_INIT_C after TPD_G;
260	      elsif rising_edge(axiClk) then
261	         r <= rin after TPD_G;
262	      end if;
263	   end process seq;
264	
265	end architecture rtl;
