528	   procedure axiSlaveWaitWriteTxn (
529	      signal axiWriteMaster  : in    AxiLiteWriteMasterType;
530	      variable axiWriteSlave : inout AxiLiteWriteSlaveType;
531	      variable writeEnable   : inout sl) is
532	   begin
533	      ----------------------------------------------------------------------------------------------
534	      -- AXI Write Logic
535	      ----------------------------------------------------------------------------------------------
536	      writeEnable := '0';
537	
538	      -- Reset resp valid
539	      if (axiWriteMaster.bready = '1') then
540	         axiWriteSlave.bvalid := '0';
541	      end if;
542	
543	      -- Check if last cycle accepted write address and write data
544	      if (axiWriteSlave.awready = '1') and (axiWriteSlave.wready = '1') then
545	
546	         -- Prevent AXI_ERRS_BRESP_AW: A slave must not give a write response before the write address. Spec: section A3.3.1 and figure A3-7.
547	         axiWriteSlave.bvalid := '1';
548	
549	      else
550	
551	         -- Incoming Write txn and last txn has concluded
552	         if (axiWriteMaster.awvalid = '1' and axiWriteMaster.wvalid = '1' and axiWriteSlave.bvalid = '0') then
553	            writeEnable := '1';
554	         end if;
555	
556	      end if;
557	
558	      axiWriteSlave.awready := '0';
559	      axiWriteSlave.wready  := '0';
560	
561	   end procedure axiSlaveWaitWriteTxn;
562	
563	   procedure axiSlaveWaitReadTxn (
564	      signal axiReadMaster  : in    AxiLiteReadMasterType;
565	      variable axiReadSlave : inout AxiLiteReadSlaveType;
566	      variable readEnable   : inout sl) is
567	   begin
568	      ----------------------------------------------------------------------------------------------
569	      -- AXI Read Logic
570	      ----------------------------------------------------------------------------------------------
571	      readEnable := '0';
572	
573	      -- Check if last cycle accepted read address
574	      if (axiReadSlave.arready = '1') then
575	
576	         -- Prevent AXI_AUXM_RCAM_UNDERFLOW: Read CAM underflow.
577	         axiReadSlave.rvalid := '1';
578	
579	      else
580	
581	         -- Reset rvalid upon rready
582	         if (axiReadMaster.rready = '1') then
583	            axiReadSlave.rvalid := '0';
584	            axiReadSlave.rdata  := (others => '0');
585	         end if;
586	
587	         -- Incoming read txn and last txn has concluded
588	         if (axiReadMaster.arvalid = '1' and axiReadSlave.rvalid = '0') then
589	            readEnable := '1';
590	         end if;
591	
592	      end if;
593	
594	      axiReadSlave.arready := '0';
595	
596	   end procedure axiSlaveWaitReadTxn;
597	
598	   procedure axiSlaveWaitTxn (
599	      signal axiWriteMaster  : in    AxiLiteWriteMasterType;
600	      signal axiReadMaster   : in    AxiLiteReadMasterType;
601	      variable axiWriteSlave : inout AxiLiteWriteSlaveType;
602	      variable axiReadSlave  : inout AxiLiteReadSlaveType;
603	      variable axiStatus     : inout AxiLiteStatusType) is
604	   begin
605	      axiSlaveWaitWriteTxn(axiWriteMaster, axiWriteSlave, axiStatus.writeEnable);
606	      axiSlaveWaitReadTxn(axiReadMaster, axiReadSlave, axiStatus.readEnable);
607	   end procedure;
608	
609	   procedure axiSlaveWriteResponse (
610	      variable axiWriteSlave : inout AxiLiteWriteSlaveType;
611	      axiResp                : in    slv(1 downto 0) := AXI_RESP_OK_C) is
612	   begin
613	      axiWriteSlave.awready := '1';
614	      axiWriteSlave.wready  := '1';
615	      axiWriteSlave.bvalid  := '0';     -- bvalid set in axiSlaveWaitWriteTxn
616	      axiWriteSlave.bresp   := axiResp;
