1025	   -- Generate evenly distributed address map
1026	   function genAxiLiteConfig (num      : positive;
1027	                              base     : slv(31 downto 0);
1028	                              baseBot  : integer range 1 to 32;
1029	                              addrBits : integer range 0 to 31)
1030	      return AxiLiteCrossbarMasterConfigArray is
1031	      variable retConf : AxiLiteCrossbarMasterConfigArray(num-1 downto 0);
1032	      variable addr    : slv(31 downto 0);
1033	   begin
1034	
1035	      -------------------------------------------------------------------------------------------
1036	      -- Note: These asserts only work in synthesis (not simulation)
1037	      -- https://forums.xilinx.com/t5/Synthesis/VHDL-assert-statement-within-function/td-p/413463
1038	      -------------------------------------------------------------------------------------------
1039	
1040	      -- Compare the baseBot to addrBits
1041	      assert (baseBot > addrBits)
1042	         report "AxiLitePkg.genAxiLiteConfig(): (baseBot > addrBits) condition not meet"
1043	         & lf & "num      = " & integer'image(num)
1044	         & lf & "base     = 0x" & hstr(base)
1045	         & lf & "baseBot  = " & integer'image(baseBot)
1046	         & lf & "addrBits = " & integer'image(addrBits)
1047	         severity failure;
1048	
1049	      -- Check that there is enough bits for the number of buses
1050	      assert (2**(baseBot-addrBits) >= num)
1051	         report "AxiLitePkg.genAxiLiteConfig(): (2**(baseBot-addrBits) >= num) condition not meet"
1052	         & lf & "num      = " & integer'image(num)
1053	         & lf & "base     = 0x" & hstr(base)
1054	         & lf & "baseBot  = " & integer'image(baseBot)
1055	         & lf & "addrBits = " & integer'image(addrBits)
1056	         severity failure;
1057	
1058	      -------------------------------------------------------------------------------------------
1059	      -- Init
1060	      -------------------------------------------------------------------------------------------
1061	      addr                     := base;
1062	      addr(baseBot-1 downto 0) := (others => '0');
1063	
1064	      -------------------------------------------------------------------------------------------
1065	      -- Generate records
1066	      -------------------------------------------------------------------------------------------
1067	      for i in 0 to num-1 loop
1068	         addr(baseBot-1 downto addrBits) := toSlv(i, baseBot-addrBits);
1069	         retConf(i).baseAddr             := addr;
1070	         retConf(i).addrBits             := addrBits;
1071	         retConf(i).connectivity         := x"FFFF";
1072	      end loop;
1073	
1074	      return retConf;
1075	   end function;
1076	
1077	   function genAxiSlaveStrobeMask (busHighBit : natural; normalOffset : natural) return slv is
1078	      variable strobeMask : slv(3 downto 0) := (others => '-');
1079	   begin
1080	      for i in busHighBit downto normalOffset loop
1081	         strobeMask(i/8) := '1';
1082	      end loop;
1083	      return strobeMask;
1084	   end function;
